import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void bankingExample() {
        // [1,3] picked; [3,5] start=3 NOT > 3, skip; [4,6] start=4 > 3, pick; [7,9] start=7 > 6, pick => 3
        assertEquals(3, new Solution().maxScheduledServices(new int[][]{{1,3},{3,5},{4,6},{7,9}}));
    }

    @Test
    void strictGapsAllCompatible() {
        // start 3 > 2 and start 5 > 4: all three services fit under strict rule
        assertEquals(3, new Solution().maxScheduledServices(new int[][]{{1,2},{3,4},{5,6}}));
    }

    @Test
    void endpointConflictBlocksAll() {
        // [1,5],[5,9],[5,8]: after picking [1,5] both remaining start at 5 which equals prevEnd => conflict
        assertEquals(1, new Solution().maxScheduledServices(new int[][]{{1,5},{5,9},{5,8}}));
    }

    @Test
    void allConflictingPickOne() {
        // All windows are identical — only one can be scheduled
        assertEquals(1, new Solution().maxScheduledServices(new int[][]{{2,6},{2,6},{2,6}}));
    }

    @Test
    void contrastWithNonOverlapping() {
        // [1,3] and [3,6]: standard non-overlap allows both; strict rule forbids (3 NOT > 3) => only 1
        assertEquals(1, new Solution().maxScheduledServices(new int[][]{{1,3},{3,6}}));
    }

    @Test
    void singleService() {
        assertEquals(1, new Solution().maxScheduledServices(new int[][]{{0,10}}));
    }

    @Test
    void emptyInput() {
        assertEquals(0, new Solution().maxScheduledServices(new int[][]{}));
    }
}
